    for i in range(len(a)+1):
        for j in combinations(a, i):
            yield j

def main():
    n = int(input())
    cards = input().split()
    unique_cards = set((i[0], int(i[1])) for i in cards)

    result = float("inf")

    for color_hints in variants("RGBYW"):
